values
  ('6f1a2c1b-34d3-40ed-abdf-8668a11c7ea4','C000011-A1','A1',null,'Unflagging Assault','Attacks 1 enemy. Has a 45% chance of placing a 60% [Decrease DEF] debuff for 2 turns. The damage of this skill increases by 10% every time this skill is used. Stacks up to 100%.','0','0','0.02 Enemy MAX HP / 2.5 ATK','Enemy MAX HP or ATK',0,'verified','worksheet Skills tab 2026-07-11','human_observation; verbatim 2026-07-10; re-keyed L0002->C000011'),
  ('6f1a2c1b-34d3-40ed-abdf-8668a11c7ea4','C000011-A2','A2',null,'Battlefield Domination','Attacks all enemies 2 times. Places a [Shield] buff on this Champion for 2 turns. The value of the shield buff is equal to 5% of this Champion''s MAX HP for each critical hit.','4','3','0.05 Enemy MAX HP / 2 ATK','Enemy MAX HP or ATK',0,'verified','worksheet Skills tab 2026-07-11','human_observation; verbatim 2026-07-10; re-keyed L0002->C000011'),
  ('6f1a2c1b-34d3-40ed-abdf-8668a11c7ea4','C000011-A3','A3',null,'Shut Down','Attacks 1 enemy 2 times. Has an 80% chance of stealing 100% of the target''s Turn Meter before attacking. This effect cannot be resisted if the target has a higher MAX HP than this Champion.','4','3','0.05 Enemy MAX HP / 3 ATK','Enemy MAX HP or ATK',0,'verified','worksheet Skills tab 2026-07-11','human_observation; verbatim 2026-07-10; re-keyed L0002->C000011'),
  ('6f1a2c1b-34d3-40ed-abdf-8668a11c7ea4','C000011-Passive','Passive',null,'Grandeur [P]','Decreases the damage taken from AoE attacks by 50%. If a target''s MAX HP is more than double this Champion''s MAX HP, this Champion''s attacks will deal damage based on the target''s MAX HP, instead of this Champion''s ATK.',null,null,null,null,0,'verified','worksheet Skills tab 2026-07-11','human_observation; verbatim 2026-07-10; re-keyed L0002->C000011'),
  ('8fc52b52-01e4-42e4-afc4-373f41d24441','E0001-A1','A1',null,'Devour All Hope','Attacks 1 enemy. Has a 30% chance of decreasing the duration of 1 random buff if the target is under a [HP Burn] debuff. Also has a 30% chance of decreasing the target''s Turn Meter by 15% if they are under a [Freeze] debuff.',null,null,'3.5','ATK',0,'pending','worksheet Skills tab 2026-07-11','ayumilove verbatim 2026-07-11'),
  ('8fc52b52-01e4-42e4-afc4-373f41d24441','E0001-A2','A2',null,'Cannibal Might','Places a [Block Debuffs] buff on all allies for 1 turn and a 25% [Strengthen] buff on all allies for 2 turns.','5','4',null,null,0,'pending','worksheet Skills tab 2026-07-11','ayumilove verbatim 2026-07-11'),
  ('8fc52b52-01e4-42e4-afc4-373f41d24441','E0001-A3','A3',null,'Frostfire Gale','Attacks all enemies. Has a 70% chance of placing a [Freeze] debuff for 1 turn on enemies whose ATK is higher than their DEF. Has a 70% chance of placing a [HP Burn] debuff for 1 turn on enemies whose DEF is equal to or higher than their ATK.','5','3','5.5','ATK',0,'pending','worksheet Skills tab 2026-07-11','ayumilove verbatim 2026-07-11'),
  ('8fc52b52-01e4-42e4-afc4-373f41d24441','E0001-P','Passive',null,'Twisted Hunger','Heals all allies by 5% of their MAX HP every time an enemy under a [HP Burn] debuff gets a turn. Fills the Turn Meters of all allies by 10% every time an enemy under a [Freeze] debuff gets a turn.',null,null,null,null,0,'pending','worksheet Skills tab 2026-07-11','ayumilove verbatim 2026-07-11'),
  ('d1ad365b-c4d7-4d72-867d-5203e3998c5c','E0002-A1','A1',null,'Humiliate','Single-target attack with a chance to place Decrease ACC.',null,null,null,null,0,'verified','worksheet Skills tab 2026-07-11',null),
