  ('a700373d-be35-4da1-83c7-381541a717fb','C000614-A1','A1',null,'Earthroot Tendril','Attacks 1 enemy. Increases the value of all [Shield] buffs on this Champion by 25%. Also increases the value of any [Shield] buffs on the ally with the lowest HP by 25%. The increased value of the [Shield] buffs cannot exceed 10,000 HP.',null,null,null,null,0,'pending','worksheet Skills tab 2026-07-11','web-sourced 2026-07-09; user-approved for seeding; slot positional — verify passives')
