  ('55e03ed1-b948-4f69-9430-52b5b44b56c9','C000352-A3','A3',null,'Eruptive Volley','Attacks all enemies. Has a 75% chance of placing a 25% [Weaken] debuff for 2 turns. Grants an Extra Turn if [Weaken] was placed on all enemies by this skill.','4 Turns',null,null,null,0,'pending','worksheet Skills tab 2026-07-11','web-sourced 2026-07-09; user-approved for seeding; slot positional — verify passives'),
  ('55e03ed1-b948-4f69-9430-52b5b44b56c9','C000352-A4','A4',null,'Explosive Phoenix [P]','Places a [Revive On Death] buff on this Champion for 2 turns when an enemy dies from a [Bomb] debuff.','6 Turns',null,null,null,0,'pending','worksheet Skills tab 2026-07-11','web-sourced 2026-07-09; user-approved for seeding; slot positional — verify passives'),
  ('9c54a7cb-717b-4896-b625-909b105b95b5','C000629-A1','A1','base','Beheading Strike','Attacks 1 enemy. Before attacking, decreases the duration of all buffs on the target by 1 turn. Also has a 75% chance of placing a [Block Buffs] debuff for 2 turns. This debuff is protected when placed on Bosses.',null,null,null,null,0,'pending','worksheet Skills tab 2026-07-11','Rebuilt from ayumilove verbatim 2026-07-11'),
