  ('95853c5c-716f-488f-bd92-5d9066bf9a06','C000640-A3','A3',null,'Glorious Revival','Revives all dead allies with 50% HP and 50% Turn Meter. Places a 25% [Strengthen] buff and a 30% [Increase SPD] buff on all allies for 2 turns.','7 Turns',null,null,null,0,'pending','worksheet Skills tab 2026-07-11','web-sourced 2026-07-09; user-approved for seeding; slot positional — verify passives'),
  ('95853c5c-716f-488f-bd92-5d9066bf9a06','C000640-P','Passive',null,'Shield of the Argolades [P]','Whenever an ally receives a debuff, places a [Shield] buff on that ally equal to 20% of their MAX HP for 1 turn. Fills the Turn Meters of all allies by 15% at the end of this Champion’s turn.',null,null,null,null,0,'pending','worksheet Skills tab 2026-07-11','web-sourced 2026-07-09; user-approved for seeding; slot positional — verify passives'),
