  ('1754846a-1e6a-49b8-9100-6fd0e1174701','C000453-A3','A3',null,'Prey on the Weak','Attacks 1 enemy. Steals all buffs from the target.','5',null,null,null,0,'pending','worksheet Skills tab 2026-07-11','web-sourced 2026-07-09; user-approved for seeding; slot positional — verify passives'),
  ('af36750e-4916-4543-b669-ea1b80e373f4','C000771-A1','A1',null,'Holy Strike','Attacks one enemy. Has a 100% chance to steal a portion of their Turn Meter and apply a [Block Active Skills] debuff.',null,null,null,null,0,'pending','worksheet Skills tab 2026-07-11','web-sourced 2026-07-09; user-approved for seeding; slot positional — verify passives'),
  ('af36750e-4916-4543-b669-ea1b80e373f4','C000771-A2','A2',null,'Divine Intervention','Removes buffs from enemies and applies a Turn Meter decrease that scales from 25% to 40% against heavily buffed targets. Applies the [Ensnare] debuff, which reduces Turn Meter boosts for targets. Can ignore [Block Debuffs] when applying [Ensnare] to enemies with three or more buffs.',null,null,null,null,0,'pending','worksheet Skills tab 2026-07-11','web-sourced 2026-07-09; user-approved for seeding; slot positional — verify passives'),
  ('af36750e-4916-4543-b669-ea1b80e373f4','C000771-A3','A3',null,'Sacred Rite','Applies an [Increase ACC] buff and one [Intercept] stack to all allies, boosts their Turn Meters by 25%, and grants Pontiff Augustin an Extra Turn.',null,null,null,null,0,'pending','worksheet Skills tab 2026-07-11','web-sourced 2026-07-09; user-approved for seeding; slot positional — verify passives'),
  ('af36750e-4916-4543-b669-ea1b80e373f4','C000771-A4','A4',null,'Vigilant Protector','Reduces the damage allies take by 25% from enemies under [Block Damage], [Veil], or [Stoneskin] buffs. Enemies who gain buffs or receive Turn Meter boosts also face a 50% chance to have their buff durations reduced by one turn.',null,null,null,null,0,'pending','worksheet Skills tab 2026-07-11','web-sourced 2026-07-09; user-approved for seeding; slot positional — verify passives'),
  ('d844a25e-4f1c-474f-a6bd-aa8ea791e2a5','C000772-A1','A1',null,'Slithering Transfer','Transfers all debuffs from herself to a target. Becomes irresistible if she is under three or more debuffs.',null,null,null,null,0,'pending','worksheet Skills tab 2026-07-11','web-sourced 2026-07-09; user-approved for seeding; slot positional — verify passives'),
  ('d844a25e-4f1c-474f-a6bd-aa8ea791e2a5','C000772-A2','A2',null,'Healing Scales','Heals all allies by 25% of her MAX HP, then applies an [Increase Defence] buff and an [Increase Speed] buff to all allies.',null,null,null,null,0,'pending','worksheet Skills tab 2026-07-11','web-sourced 2026-07-09; user-approved for seeding; slot positional — verify passives'),
  ('d844a25e-4f1c-474f-a6bd-aa8ea791e2a5','C000772-A3','A3',null,'Viper''s Revival','Revives one ally with 100% HP and 50% Turn Meter. Resets the cooldowns of all that ally''s skills.',null,null,null,null,0,'pending','worksheet Skills tab 2026-07-11','web-sourced 2026-07-09; user-approved for seeding; slot positional — verify passives'),
  ('d844a25e-4f1c-474f-a6bd-aa8ea791e2a5','C000772-A4','A4',null,'Debuff Absorption & Turn Meter Boost','At the start of her turn, transfers 1 random debuff from each ally to herself (excluding crowd control debuffs). At the end of her turn, fills the Turn Meters of all allies by 10%, plus an additional 2% for each debuff on this Champion.',null,null,null,null,0,'pending','worksheet Skills tab 2026-07-11','web-sourced 2026-07-09; user-approved for seeding; slot positional — verify passives'),
  ('3a2201b8-91ef-4a9c-aeef-9f181d84b92e','C000773-A1','A1','base','Wrist Blades','Attacks 1 enemy. Heals this Champion by 30% of the damage dealt. [Passive Effect] Whenever this Champion successfully Evades an enemy skill and all of its accompanying effects, counterattacks with this skill.',null,null,null,null,0,'pending','worksheet Skills tab 2026-07-11','Rebuilt from ayumilove verbatim 2026-07-11'),
  ('3a2201b8-91ef-4a9c-aeef-9f181d84b92e','C000773-A2','A2','base','Smart Disc','Attacks all enemies 2 times. After hitting the initially selected enemy, all other enemies will be hit in a random order. For the first hit, the damage received by the initially selected enemy will be increased by 75%. Each subsequent enemy hit following the initial hit will receive 15% less bonus damage (reduces to 15% bonus damage). Also destroys each enemy''s MAX HP by 30% of the damage dealt (stacks up to 50%). For the second hit, the damage received by the initially selected enemy will be increased by 15%. Each subsequent enemy hit following the initial hit will receive 15% more bonus damage (stacks up to 75% bonus damage). This attack ignores 15% of each target''s DEF if this Champion is under a [Veil] or [Perfect Veil] buff.',null,null,null,null,0,'pending','worksheet Skills tab 2026-07-11','Rebuilt from ayumilove verbatim 2026-07-11'),
  ('3a2201b8-91ef-4a9c-aeef-9f181d84b92e','C000773-A3','A3','base','Combistick Throw','Attacks 1 enemy. Before attacking, places a [Hunter''s Gaze] debuff for 1 turn. This debuff cannot be resisted if this Champion is under a [Veil] or [Perfect Veil] buff. If this attack kills an enemy, places a [Block Revive] debuff on the target and a [Hunter''s Gaze] debuff on a random alive enemy for 1 turn. If this attack does not kill an enemy, places a [Perfect Veil] buff on this Champion for 2 turns and fills their Turn Meter by 50%.',null,null,null,null,0,'pending','worksheet Skills tab 2026-07-11','Rebuilt from ayumilove verbatim 2026-07-11'),
  ('3a2201b8-91ef-4a9c-aeef-9f181d84b92e','C000773-P','Passive','base','Yautja Cloak','At the start of each Round, places a [Perfect Veil] buff on this Champion for 1 turn. Before this Champion takes a turn, also has an initial 50% chance to Evade an enemy skill and all of its accompanying effects. This initial chance reduces to 0% after this Champion''s first turn in a Round. Whenever this Champion kills an enemy, grants this Champion a 20% chance to Evade enemy skills and accompanying effects (stacks up to 60%).',null,null,null,null,0,'pending','worksheet Skills tab 2026-07-11','Rebuilt from ayumilove verbatim 2026-07-11'),
  ('2f4786f2-f294-4cb7-8b6c-1e94ce6c66ea','C000775-A1','A1',null,'Rapacious Staff','Attacks 1 enemy 2 times. Heals the ally with the lowest HP by 5% of this Champion’s MAX HP after each hit.',null,null,null,null,0,'pending','worksheet Skills tab 2026-07-11','web-sourced 2026-07-09; user-approved for seeding; slot positional — verify passives'),
  ('2f4786f2-f294-4cb7-8b6c-1e94ce6c66ea','C000775-A2','A2',null,'Shed Skin','Removes all debuffs from all allies, then heals them by 10% of their MAX HP. Heals each ally by an extra 5% of their MAX HP for each debuff removed from them. Also places a [Block Debuffs] buff on all allies for 2 turns.','4 Turns',null,null,null,0,'pending','worksheet Skills tab 2026-07-11','web-sourced 2026-07-09; user-approved for seeding; slot positional — verify passives'),
  ('2f4786f2-f294-4cb7-8b6c-1e94ce6c66ea','C000775-A3','A3',null,'Immortal Serpent','Revives all dead allies with 50% HP and 50% Turn Meter, then places a 25% [Strengthen] buff on all allies for 2 turns.','7 Turns',null,null,null,0,'pending','worksheet Skills tab 2026-07-11','web-sourced 2026-07-09; user-approved for seeding; slot positional — verify passives'),
