  ('9abf2a7a-cbb4-485b-989a-ec1fdcd9dbdb','C000488-A3','A3',null,'Hold the Front','Has a 75% chance of placing a [Provoke] debuff on all enemies for 1 turn. Places a [Counterattack] and a 15% [Continuous Heal] buff on this Champion for 2 turns.','4',null,null,null,0,'pending','worksheet Skills tab 2026-07-11','web-sourced 2026-07-09; user-approved for seeding; slot positional — verify passives'),
  ('9f835dbc-9f9b-41bf-b67a-ff2dffdba335','C000822-A1','A1','base','Hexpyre','Attacks 1 enemy. Has a 50% chance of applying a [Debuff Spread] effect, taking a [Hex] debuff and placing it on all enemies. If the target isn''t under a [Hex] debuff, will spread one other random debuff instead.',null,null,null,null,0,'pending','worksheet Skills tab 2026-07-11','Rebuilt from ayumilove verbatim 2026-07-11'),
