  ('93ce1922-3ef0-4fff-aafb-9ae5c48032d2','C000841-A4','A4',null,'Passive 1','Gradually weakens attack-based opponents up to a maximum of 50% in Arena or Waves, and 25% against Bosses. Places a [Fear] debuff on any Orc, Ogryn, Undead Horde, or Demonspawn champion at the start of battle.',null,null,null,null,0,'pending','worksheet Skills tab 2026-07-11','web-sourced 2026-07-09; user-approved for seeding; slot positional — verify passives'),
  ('93ce1922-3ef0-4fff-aafb-9ae5c48032d2','C000841-A5','A5',null,'Passive 2','Reduces all incoming skill damage by 50%. This effect decreases this Champion''s MAX HP.',null,null,null,null,0,'pending','worksheet Skills tab 2026-07-11','web-sourced 2026-07-09; user-approved for seeding; slot positional — verify passives'),
