  ('68010857-61fc-4dc1-8280-c7b53ac8350f','C000006-ALT-Passive','Passive','alternate','Tanglethorn [P]','When attacked, places a 30% [Decrease SPD] debuff on the attacker for 2 turns. Occurs once per hit. Also decreases the damage taken by all allies from skills by 20%. This Champion will receive that damage instead.',null,null,null,null,0,'pending','worksheet Skills tab 2026-07-11','human_observation; web-sourced 2026-07-10; Mythical champion'),
  ('c0d73b3a-8236-4e9a-afe2-bb4c762b736e','C000007-A1','A1','base','Song of Steel','Attacks 1 enemy. Places an extra hit if the target is under a [Deathbrand] debuff. Decreases the target''s HP and DEF by 10% (stacks up to 30%). This effect does not work against Bosses.',null,null,null,null,0,'pending','worksheet Skills tab 2026-07-11','human_observation; web-sourced 2026-07-10; Mythical champion'),
  ('c0d73b3a-8236-4e9a-afe2-bb4c762b736e','C000007-A2','A2','base','White-Hot Rage','Attacks 1 enemy. Before attacking, places a [Block Passive Skills] debuff for 1 turn. Will ignore 50% of the target''s DEF, as well as [Block Damage] and [Unkillable] buffs. If the initial target is killed, will repeat the attack against all enemies and ignore 25% of each target''s DEF. Will also decrease the cooldown of the Arctic Howl skill by 2 turns if the initial target is killed while under a [Deathbrand] debuff.','4 Turns',null,null,null,0,'pending','worksheet Skills tab 2026-07-11','human_observation; web-sourced 2026-07-10; Mythical champion'),
  ('c0d73b3a-8236-4e9a-afe2-bb4c762b736e','C000007-A3','A3','base','Arctic Howl','Places a 50% [Increase ATK] buff and a 50% [Increase ACC] buff on all allies for 3 turns. Places a [Deathbrand] debuff on all enemies for 2 turns. Then grants an Extra Turn.','5 Turns',null,null,null,0,'pending','worksheet Skills tab 2026-07-11','human_observation; web-sourced 2026-07-10; Mythical champion'),
