  ('cb2ee945-37d2-42d8-98de-fba6b053f626','C000921-ALT-A3','A3','alternate','Ruthless Agent','Places a 15% [Shatter] buff and a 30% [Increase C.RATE] buff on this Champion for 3 turns. Places a [True Fear] debuff on all enemies for 1 turn. Targets whose ATK is equal to or lower than this Champion''s ATK cannot resist this effect. Grants an Extra Turn.','5 Turns',null,null,null,0,'pending','worksheet Skills tab 2026-07-11','ayumilove verbatim 2026-07-11'),
  ('cb2ee945-37d2-42d8-98de-fba6b053f626','C000921-ALT-A4','A4','alternate','Metamorph','Transforms this Champion into their Base Form. Then grants an Extra Turn.','4 Turns',null,null,null,0,'pending','worksheet Skills tab 2026-07-11','human_observation; web-sourced 2026-07-09; Mythical champion'),
  ('cb2ee945-37d2-42d8-98de-fba6b053f626','C000921-ALT-Passive','Passive','alternate','Vile Murderess','Deals 15% more damage for each dead ally. Each critical hit boosts this Champion''s Turn Meter by 10% for each dead ally.',null,null,null,null,0,'pending','worksheet Skills tab 2026-07-11','ayumilove verbatim 2026-07-11'),
  ('61b6927f-209f-4ccf-8801-16fdcb4c1e15','C000922-A1','A1','base','Shadow Lash','Attacks 1 enemy with 1 random ally from the Shadowkin Faction. The ally joining the attack will use their default skill. Places a [Shield] buff equal to 10% of this Champion''s MAX HP on the ally with the lowest HP for 2 turns.',null,null,null,null,0,'pending','worksheet Skills tab 2026-07-11','human_observation; web-sourced 2026-07-09; Mythical champion'),
  ('61b6927f-209f-4ccf-8801-16fdcb4c1e15','C000922-A2','A2','base','Silkensnare','Attacks all enemies. Decreases the duration of all enemy buffs and all ally debuffs by 1 turn. Then, increases the duration of all enemy debuffs and all ally buffs by 1 turn.','3 Turns',null,null,null,0,'pending','worksheet Skills tab 2026-07-11','human_observation; web-sourced 2026-07-09; Mythical champion'),
