  ('2341c4f3-f43c-4671-8c30-bed99ca6c9a7','C000929-ALT-Passive','Passive','alternate','Angelic Aegis [P]','Places a 60% [Increase DEF] buff and a 50% [Increase RES] buff on this Champion for 2 turns at the start of each turn.',null,null,null,null,0,'pending','worksheet Skills tab 2026-07-11','human_observation; web-sourced 2026-07-09; Mythical champion'),
  ('d4964e4c-67af-4137-87cd-d31687bfe007','C000930-A1','A1','base','Astral Storm','Attacks all enemies. Fills the Turn Meters of all allies by 10%. Also fills the Turn Meter of each ally by an extra 5% if they have any active buffs placed on them by this Champion.',null,null,null,null,0,'pending','worksheet Skills tab 2026-07-11','human_observation; web-sourced 2026-07-09; Mythical champion'),
  ('d4964e4c-67af-4137-87cd-d31687bfe007','C000930-A2','A2','base','Stellar Embryo','Removes all debuffs from all allies, then heals them by 25% of this Champion''s MAX HP. Also fills the Turn Meters of all allies by 15%, and places a [Block Debuffs] buff on them for 2 turns.','4 Turns',null,null,null,0,'pending','worksheet Skills tab 2026-07-11','human_observation; web-sourced 2026-07-09; Mythical champion'),
  ('d4964e4c-67af-4137-87cd-d31687bfe007','C000930-A3','A3','base','Part the Veil','Revives all dead allies with 50% HP and 50% Turn Meter. Also places a [Perfect Veil] buff on all allies, except this Champion, for 2 turns.','6 Turns',null,null,null,0,'pending','worksheet Skills tab 2026-07-11','human_observation; web-sourced 2026-07-09; Mythical champion'),
  ('d4964e4c-67af-4137-87cd-d31687bfe007','C000930-A4','A4','base','Metamorph','Transforms this Champion into their Alternate Form. Then grants an Extra Turn.','4 Turns',null,null,null,0,'pending','worksheet Skills tab 2026-07-11','human_observation; web-sourced 2026-07-09; Mythical champion'),
  ('d4964e4c-67af-4137-87cd-d31687bfe007','C000930-Passive','Passive','base','Eternal Beyonder [P]','[Passive Effect] This Champion receives 5% less damage for each 100 RES on this Champion (stacks up to 25%). [Active Effect] Prevents this Champion''s death and keeps them alive on 1 HP when receiving fatal damage, then equalizes their HP. The HP level of this Champion will be brought up to the average HP level of the team.','3 Turns',null,null,null,0,'pending','worksheet Skills tab 2026-07-11','human_observation; web-sourced 2026-07-09; Mythical champion'),
  ('d4964e4c-67af-4137-87cd-d31687bfe007','C000930-ALT-A1','A1','alternate','Uncreation Beam','Attacks all enemies. Decreases the Turn Meters of all enemies by 10%. Decreases the Turn Meter of each enemy by an extra 5% if they are under a [Block Active Skills], [Decrease RES], or [Stun] debuff placed by this Champion.',null,null,null,null,0,'pending','worksheet Skills tab 2026-07-11','human_observation; web-sourced 2026-07-10; Mythical champion'),
  ('d4964e4c-67af-4137-87cd-d31687bfe007','C000930-ALT-A2','A2','alternate','Eclipse Rend','Attacks all enemies. Before attacking, removes all buffs from all enemies. Then, places a [Block Active Skills] debuff for 2 turns. This attack will not trigger counterattacks.','4 Turns',null,null,null,0,'pending','worksheet Skills tab 2026-07-11','human_observation; web-sourced 2026-07-10; Mythical champion'),
  ('d4964e4c-67af-4137-87cd-d31687bfe007','C000930-ALT-A3','A3','alternate','Dark Nebula','Places a 50% [Increase ACC] buff on all allies for 2 turns. Then, places a 50% [Decrease RES] debuff on all enemies for 2 turns, and a [Stun] debuff on all enemies for 1 turn.','4 Turns',null,null,null,0,'pending','worksheet Skills tab 2026-07-11','human_observation; web-sourced 2026-07-10; Mythical champion'),
  ('d4964e4c-67af-4137-87cd-d31687bfe007','C000930-ALT-A4','A4','alternate','Metamorph','Transforms this Champion into their Base Form. Then grants an Extra Turn.','4 Turns',null,null,null,0,'pending','worksheet Skills tab 2026-07-11','human_observation; web-sourced 2026-07-10; Mythical champion'),
  ('d4964e4c-67af-4137-87cd-d31687bfe007','C000930-ALT-Passive','Passive','alternate','Starlight Reflect [P]','[Passive Effect] Increases this Champion''s ACC equal to 75% of their RES when placing debuffs or activating instant effects. [Active Effect] If an enemy''s ACC is higher than this Champion''s RES, has a 50% chance of transferring any [Fear], [True Fear], [Freeze], [Provoke], [Sleep], [Stun], or [Petrification] debuffs back to the enemy when placing these debuffs on this Champion.','3 Turns',null,null,null,0,'pending','worksheet Skills tab 2026-07-11','human_observation; web-sourced 2026-07-10; Mythical champion'),
  ('f6789af3-3a4d-4423-98e8-84101902358c','C000931-A1','A1','base','Reaping Cull','Attacks 1 enemy 2 times. Each hit has an extra 20% chance of inflicting a critical hit. Each hit restores this Champion''s destroyed MAX HP, equal to the damage inflicted. Each hit also heals this Champion by 30% of the damage inflicted. Grants an Extra Turn if this attack kills an enemy.',null,null,'2.1','ATK',0,'pending','worksheet Skills tab 2026-07-11','ayumilove verbatim 2026-07-11'),
  ('f6789af3-3a4d-4423-98e8-84101902358c','C000931-A2','A2','base','Horde of Calamity','Attacks 1 enemy 4 times. Each hit has an extra 20% chance of inflicting a critical hit. The first hit will ignore 10% of the target''s DEF. Each subsequent hit will ignore an additional 5% of the target''s DEF. The first hit places a [Block Buffs] debuff for 2 turns. The second hit places a 60% [Decrease DEF] debuff for 2 turns. The third hit places a 25% [Weaken] debuff for 2 turns. The fourth hit places a 30% [Decrease SPD] debuff for 2 turns.','3 Turns',null,'1.8','ATK',0,'pending','worksheet Skills tab 2026-07-11','ayumilove verbatim 2026-07-11'),
  ('f6789af3-3a4d-4423-98e8-84101902358c','C000931-A3','A3','base','Necroclysm','Attacks all enemies. This attack is always critical, and will ignore 20% of each enemy''s DEF. If this attack kills an enemy, places an [Unkillable] buff on this Champion for 1 turn. If this attack kills 2 or more enemies, places an [Unkillable] buff on this Champion for 2 turns instead.','5 Turns',null,'4.8','ATK',0,'pending','worksheet Skills tab 2026-07-11','ayumilove verbatim 2026-07-11'),
  ('f6789af3-3a4d-4423-98e8-84101902358c','C000931-A4','A4','base','Metamorph','Transforms this Champion into their Alternate Form. Then grants an Extra Turn.','4 Turns',null,null,null,0,'pending','worksheet Skills tab 2026-07-11','human_observation; web-sourced 2026-07-09; Mythical champion'),
  ('f6789af3-3a4d-4423-98e8-84101902358c','C000931-Passive','Passive','base','Immortal Creation','At the start of this Champion''s turn, places a [Shield] buff equal to 50% of this Champion''s MAX HP on them for 1 turn. Also places a 50% [Increase ATK] buff on this Champion for 1 turn.',null,null,null,null,0,'pending','worksheet Skills tab 2026-07-11','ayumilove verbatim 2026-07-11'),
  ('f6789af3-3a4d-4423-98e8-84101902358c','C000931-ALT-A1','A1','alternate','Fell Scythe','Attacks 1 enemy. Has an extra 20% chance of inflicting a critical hit. After attacking, transfers all debuffs from this Champion to the target. If the target is under a [Hex] debuff before the attack, transfers all debuffs from this Champion to the target before attacking instead.',null,null,'4','ATK',0,'pending','worksheet Skills tab 2026-07-11','ayumilove verbatim 2026-07-11'),
  ('f6789af3-3a4d-4423-98e8-84101902358c','C000931-ALT-A2','A2','alternate','Final Testament','Attacks all enemies. Has an extra 20% chance of inflicting a critical hit. Before attacking, removes all debuffs from this Champion. Will ignore 20% of each enemy''s DEF. Will ignore 35% of each target''s DEF instead if they are under a [Hex] debuff. Damage increases by 10% for each debuff on each target.',null,null,'4.2 ATK * (1 + 0.1 * target debuffs)','formula',0,'pending','worksheet Skills tab 2026-07-11','ayumilove verbatim 2026-07-11'),
  ('f6789af3-3a4d-4423-98e8-84101902358c','C000931-ALT-A3','A3','alternate','Termination','Attacks all enemies. Has an extra 20% chance of inflicting a critical hit. Before attacking, places a [Hex] debuff and a 60% [Decrease DEF] debuff for 2 turns. Will ignore [Life Barrier], [Poison Cloud], and [Ally Protection] buffs.',null,null,'4.4','ATK',0,'pending','worksheet Skills tab 2026-07-11','ayumilove verbatim 2026-07-11'),
  ('f6789af3-3a4d-4423-98e8-84101902358c','C000931-ALT-Passive','Passive','alternate','Banquet of Death','Whenever this Champion attacks an enemy under a [Hex] debuff, heals this Champion by 30% of the damage inflicted. Also increases this Champion''s ATK by 20% for each enemy under a [Hex] debuff.',null,null,null,null,0,'pending','worksheet Skills tab 2026-07-11','ayumilove verbatim 2026-07-11'),
  ('148af4d8-c73e-43ca-a118-231c47a487c5','C000932-A1','A1','base','Serpentia''s Storm','Attacks 1 enemy. Heals all allies by 5% of this Champion''s MAX HP. Fills this Champion''s Turn Meter by 5% per each alive ally, and by an additional 2.5% per each alive enemy.',null,null,'0.27','HP',0,'pending','worksheet Skills tab 2026-07-11','ayumilove verbatim 2026-07-11'),
  ('148af4d8-c73e-43ca-a118-231c47a487c5','C000932-A2','A2','base','Deranged Fortitude','Removes all debuffs from all allies, then places a [Perfect Veil] buff on all allies, except this Champion, for 2 turns. Places a [Stone Skin] buff on this Champion for 1 turn.','4 Turns',null,null,null,0,'pending','worksheet Skills tab 2026-07-11','ayumilove verbatim 2026-07-11'),
  ('148af4d8-c73e-43ca-a118-231c47a487c5','C000932-A3','A3','base','Unnatural Regeneration','Revives all dead allies with 50% HP and 50% Turn Meter. Places an [Unkillable] buff on all allies for 2 turns.','6 Turns',null,null,null,0,'pending','worksheet Skills tab 2026-07-11','ayumilove verbatim 2026-07-11'),
  ('148af4d8-c73e-43ca-a118-231c47a487c5','C000932-A4','A4','base','Metamorph','Transforms this Champion into their Alternate Form. Then grants an Extra Turn.','4 Turns',null,null,null,0,'pending','worksheet Skills tab 2026-07-11','human_observation; web-sourced 2026-07-09; Mythical champion'),
  ('148af4d8-c73e-43ca-a118-231c47a487c5','C000932-Passive','Passive','base','Heinous Protection','Every 7 turns, equalizes the HP of all allies. The HP levels of all allies will be brought to the average HP level of the team. Allies will receive 1% less damage for every 2% HP lost (stacks up to 25%).',null,null,null,null,0,'pending','worksheet Skills tab 2026-07-11','ayumilove verbatim 2026-07-11'),
  ('148af4d8-c73e-43ca-a118-231c47a487c5','C000932-ALT-A1','A1','alternate','I Will Find You','Attacks 1 enemy. Destroys the target''s SPD by 3 (stacks up to 30). Decreases the target''s Turn Meter by 5% per each alive ally, and by an additional 2.5% per each alive enemy.',null,null,'0.29','HP',0,'pending','worksheet Skills tab 2026-07-11','ayumilove verbatim 2026-07-11'),
  ('148af4d8-c73e-43ca-a118-231c47a487c5','C000932-ALT-A2','A2','alternate','Baleful Onslaught','Attacks all enemies. Before attacking, steals all buffs from all enemies. Places a [Block Buffs] debuff and a 60% [Decrease DEF] debuff for 2 turns on all enemies. If an enemy''s SPD is lower than this Champion''s SPD, these debuffs will be protected.',null,null,'0.27','HP',0,'pending','worksheet Skills tab 2026-07-11','ayumilove verbatim 2026-07-11'),
  ('148af4d8-c73e-43ca-a118-231c47a487c5','C000932-ALT-A3','A3','alternate','Somnolent Whisper','Places a [Sleep] debuff for 1 turn and a 30% [Decrease SPD] debuff for 2 turns on all enemies. If an enemy''s SPD is lower than this Champion''s SPD, the [Decrease SPD] debuff will be protected. Then decreases the Turn Meters of all enemies by 25%.',null,null,null,null,0,'pending','worksheet Skills tab 2026-07-11','ayumilove verbatim 2026-07-11'),
  ('148af4d8-c73e-43ca-a118-231c47a487c5','C000932-ALT-Passive','Passive','alternate','They Are Beneath Me','This Champion is immune to [Block Active Skills] debuffs. When allies attack, their damage is increased by 25% of their target''s current Turn Meter.',null,null,null,null,0,'pending','worksheet Skills tab 2026-07-11','ayumilove verbatim 2026-07-11'),
  ('6b6a6574-f30a-4a07-a433-1db2634519c0','C000933-A1','A1','base','Quick Draw','Attacks 1 enemy. Has a 50% chance of attacking another enemy if they are under a [Leech] debuff. Also places a [Perfect Veil] buff on this Champion for 1 turn.',null,null,null,null,0,'pending','worksheet Skills tab 2026-07-11','human_observation; web-sourced 2026-07-09; Mythical champion'),
  ('6b6a6574-f30a-4a07-a433-1db2634519c0','C000933-A2','A2','base','Sanguine Darts','Attacks 4 times at random. Each hit increases this Champion''s ATK and HP by 5% while in their Base Form (stacks up to 100%). If a target is under a [Leech] debuff, this Champion''s ATK and HP are increased by 10% instead. Damage inflicted by this skill increases by 15% for each [Leech] debuff on the enemy team.','3 Turns',null,null,null,0,'pending','worksheet Skills tab 2026-07-11','human_observation; web-sourced 2026-07-09; Mythical champion'),
  ('6b6a6574-f30a-4a07-a433-1db2634519c0','C000933-A3','A3','base','Bloody Typhoon','Attacks all enemies. Places a 60% [Decrease DEF] debuff and a [Leech] debuff for 2 turns. Places an extra hit on enemies under 2 or more debuffs.','3 Turns',null,null,null,0,'pending','worksheet Skills tab 2026-07-11','human_observation; web-sourced 2026-07-09; Mythical champion'),
  ('6b6a6574-f30a-4a07-a433-1db2634519c0','C000933-A4','A4','base','Metamorph','Transforms this Champion into their Alternate Form. Then grants an Extra Turn.','4 Turns',null,null,null,0,'pending','worksheet Skills tab 2026-07-11','human_observation; web-sourced 2026-07-09; Mythical champion'),
  ('6b6a6574-f30a-4a07-a433-1db2634519c0','C000933-Passive','Passive','base','Vornspore''s Hunger [P]','Fills this Champion''s Turn Meter by 5% every time they attack a target under a [Leech] debuff. Inflicts 25% more damage to enemies under a [Leech] debuff.',null,null,null,null,0,'pending','worksheet Skills tab 2026-07-11','human_observation; web-sourced 2026-07-09; Mythical champion'),
  ('c0d73b3a-8236-4e9a-afe2-bb4c762b736e','C000007-ALT-A1','A1','alternate','Tempest of Swords','Attacks 1 enemy 2 times. Places a [Stun] debuff for 1 turn. If this Champion''s MAX HP is equal to or higher than the target''s, this debuff cannot be resisted.',null,null,null,null,0,'pending','worksheet Skills tab 2026-07-11','human_observation; web-sourced 2026-07-10; Mythical champion | alt skill name shared with Blood Marchioness Mina alt - distinct kit, Champion ID keeps separate'),
  ('c0d73b3a-8236-4e9a-afe2-bb4c762b736e','C000007-ALT-A2','A2','alternate','Goading Roar','Places a [Provoke] debuff on all enemies for 1 turn. If the target is a Boss, places a [Provoke] debuff for 2 turns instead. If this Champion''s MAX HP is equal to or higher than the target''s, these debuffs cannot be resisted. Places a 25% [Strengthen] buff on all allies for 2 turns. Also places a [Counterattack] buff on this Champion for 2 turns.','4 Turns',null,null,null,0,'pending','worksheet Skills tab 2026-07-11','human_observation; web-sourced 2026-07-10; Mythical champion'),
  ('c0d73b3a-8236-4e9a-afe2-bb4c762b736e','C000007-ALT-A3','A3','alternate','Glacial Rupture','Attacks all enemies. Before attacking, places a 60% [Decrease DEF] debuff on all enemies for 2 turns. If this Champion''s MAX HP is equal to or higher than the target''s, this debuff cannot be resisted. This attack deals single-target damage to each target individually, rather than AoE damage. Will ignore 30% of each target''s DEF. Places an extra hit on Bosses, and enemies under [Stun] or [Provoke] debuffs. If a target is a Boss, or is under [Stun] or [Provoke] debuffs, will ignore 50% DEF instead.','4 Turns',null,null,null,0,'pending','worksheet Skills tab 2026-07-11','human_observation; web-sourced 2026-07-10; Mythical champion'),
  ('c0d73b3a-8236-4e9a-afe2-bb4c762b736e','C000007-ALT-A4','A4','alternate','Metamorph','Transforms this Champion into their Base Form. Then grants an Extra Turn.','4 Turns',null,null,null,0,'pending','worksheet Skills tab 2026-07-11','human_observation; web-sourced 2026-07-10; Mythical champion'),
  ('c0d73b3a-8236-4e9a-afe2-bb4c762b736e','C000007-ALT-Passive','Passive','alternate','Bear-Heart [P]','[Passive Effect] Every time a Champion is killed, increases this Champion''s HP and DEF by 20% (stacks up to 100%). Immune to [Freeze], [Stun] and [Provoke] debuffs. [Active Effect] Whenever an enemy attempts to place a [Freeze], [Stun] or [Provoke] debuff on this Champion, instantly activates the Glacial Rupture skill. This will not put the Glacial Rupture skill on cooldown.','2 Turns',null,null,null,0,'pending','worksheet Skills tab 2026-07-11','human_observation; web-sourced 2026-07-10; Mythical champion'),
  ('3aa9cc69-dd9e-4100-b75a-951e34497761','C000910-ALT-A1','A1','alternate','Hammerflame','Attacks 1 enemy. Will ignore 10% of the target''s DEF. Will ignore an additional 5% of the target''s DEF for each active [HP Burn] debuff on the enemy team (stacks up to 35% total Ignore DEF). Places a 50% [Decrease ATK] debuff on the target for 2 turns. Attacks all enemies instead if this Champion is under a [Magma Shield] buff. Will ignore 10% of each target''s DEF. Will ignore an additional 5% of each target''s DEF for each active [HP Burn] debuff on the enemy team (stacks up to 35% total Ignore DEF). Places a 50% [Decrease ATK] debuff on all enemies for 2 turns.',null,null,null,null,0,'pending','worksheet Skills tab 2026-07-11','human_observation; web-sourced 2026-07-10; Mythical champion'),
  ('3aa9cc69-dd9e-4100-b75a-951e34497761','C000910-ALT-A2','A2','alternate','Burning Tempest','Attacks all enemies 2 times. Each hit decreases each target''s DEF by 3% (stacks up to 30%). Each hit also deals additional pure damage to each target equal to 2% of their MAX HP for each turn remaining on all [HP Burn] debuffs on all enemies (stacks up to 15%). This additional pure damage is always normal and will ignore 100% of each target''s DEF. Cannot exceed 3% of Boss and minion MAX HP. Does not count as a hit.','3 Turns',null,null,null,0,'pending','worksheet Skills tab 2026-07-11','human_observation; web-sourced 2026-07-10; Mythical champion'),
  ('3aa9cc69-dd9e-4100-b75a-951e34497761','C000910-ALT-A3','A3','alternate','Total Incineration','Attacks all enemies. Before attacking, places a [HP Burn] debuff on all enemies for 3 turns and instantly activates one tick of all [HP Burn] debuffs on all enemies. Will ignore 25% of each target''s DEF. Will ignore an additional 5% for each active [HP Burn] debuff on the enemy team (stacks up to 50% total Ignore DEF). Places a 60% [Decrease DEF] debuff on all enemies for 2 turns.','3 Turns',null,null,null,0,'pending','worksheet Skills tab 2026-07-11','human_observation; web-sourced 2026-07-10; Mythical champion'),
  ('3aa9cc69-dd9e-4100-b75a-951e34497761','C000910-ALT-A4','A4','alternate','Metamorph','Transforms this Champion into their Base Form. Then grants an Extra Turn.','4 Turns',null,null,null,0,'pending','worksheet Skills tab 2026-07-11','human_observation; web-sourced 2026-07-10; Mythical champion'),
  ('3aa9cc69-dd9e-4100-b75a-951e34497761','C000910-ALT-Passive','Passive','alternate','Fire Incarnate [P]','[Active Effect] When hit by an enemy under a [HP Burn] debuff, places a [Magma Shield] buff equal to 300% of this Champion''s ATK on this Champion for 1 turn. [Passive Effect] The damage enemies receive from [HP Burn] debuffs will ignore [Block Damage] and [Unkillable] buffs. This Champion & their allies deal 15% more damage against enemies under [HP Burn] debuffs. If there are multiple Champions on the team with this skill, only one will activate. This skill will not activate on duplicate copies of this Champion, if this particular Champion is dead.','1 Turns',null,null,null,0,'pending','worksheet Skills tab 2026-07-11','human_observation; web-sourced 2026-07-10; Mythical champion'),
  ('46bbb3bb-6b80-4364-9083-27b32649599d','C000003-ALT-A1','A1','alternate','Gildthorn Assault','Attacks 1 enemy. Has a 50% chance of placing a 60% [Decrease DEF] debuff on all enemies for 1 turn.',null,null,null,null,0,'pending','worksheet Skills tab 2026-07-11','human_observation; web-sourced 2026-07-10; Mythical champion'),
  ('46bbb3bb-6b80-4364-9083-27b32649599d','C000003-ALT-A2','A2','alternate','Palisade Breaker','Attacks all enemies. Places a 50% [Decrease RES] debuff, a 25% [Weaken] debuff, and an [Enfeeble] debuff on all enemies for 2 turns. If enemies have 50% HP or less, the [Enfeeble] debuff cannot be removed. Also decreases the Turn Meter of all enemies by 15%.','4 Turns',null,null,null,0,'pending','worksheet Skills tab 2026-07-11','human_observation; web-sourced 2026-07-10; Mythical champion'),
  ('46bbb3bb-6b80-4364-9083-27b32649599d','C000003-ALT-A3','A3','alternate','Roar of Kitherus','Attacks all enemies. Before attacking, removes all buffs from all enemies and places a [Block Buffs] debuff on all enemies without buffs for 2 turns. If the target is a Boss, the damage inflicted is equal to 10% of their MAX HP.','4 Turns',null,null,null,0,'pending','worksheet Skills tab 2026-07-11','human_observation; web-sourced 2026-07-10; Mythical champion'),
  ('46bbb3bb-6b80-4364-9083-27b32649599d','C000003-ALT-A4','A4','alternate','Metamorph','Transforms this Champion into their Base Form. Then grants an Extra Turn.','4 Turns',null,null,null,0,'pending','worksheet Skills tab 2026-07-11','human_observation; web-sourced 2026-07-10; Mythical champion'),
  ('46bbb3bb-6b80-4364-9083-27b32649599d','C000003-ALT-Passive','Passive','alternate','Lionheart [P]','Increases this Champion''s ACC by 10 for each buff on each enemy. Each critical hit inflicted by allies decreases the Turn Meters of all enemies by 5%. If there are multiple Champions on the team with this skill, only one will activate.',null,null,null,null,0,'pending','worksheet Skills tab 2026-07-11','human_observation; web-sourced 2026-07-10; Mythical champion'),
