  ('917262ec-3487-440e-b2d9-9984d3e2b9a9','C000912-ALT-Passive','Passive','alternate','Frosty Resolve [P]','Counterattacks with the Rimecleave skill whenever an enemy increases the cooldown of any of this Champion''s skills. Whenever an ally is killed, has a 50% chance of placing a [Freeze] debuff on all enemies for 1 turn. This chance increases to 100% and cannot be blocked or resisted by enemies from the Gaellen Pact.',null,null,null,null,0,'pending','worksheet Skills tab 2026-07-11','human_observation; web-sourced 2026-07-10; Mythical champion'),
  ('06cae4d7-63b0-40a8-9c12-0aa9b4136cba','C000913-A1','A1','base','Seismic Quake','Attacks 1 enemy. Will ignore 5% of the target''s DEF for each buff on this Champion.',null,null,null,null,0,'pending','worksheet Skills tab 2026-07-11','human_observation; web-sourced 2026-07-10; Mythical champion'),
